const rows = $input.all();
if (rows.length === 0) {
  return [{ json: { output: 'No tenés presupuestos definidos todavía. Podés crear uno diciendo, por ejemplo: \"poné un presupuesto de 50000 en Comida\".' } }];
}
const lines = ['📊 Presupuestos de este mes:'];
for (const r of rows) {
  const j = r.json;
  const lim = Number(j.monto_limite);
  const gastado = Number(j.gastado);
  const pct = lim > 0 ? Math.round((gastado / lim) * 100) : 0;
  const restante = lim - gastado;
  let marca = '';
  if (gastado > lim) marca = ' ⚠️ superado';
  else if (pct >= 80) marca = ' ⚠️ cerca del límite';
  lines.push(`• ${j.categoria}: $${gastado} / $${lim} (${pct}%) — restante $${restante}${marca}`);
}
return [{ json: { output: lines.join('
') } }];
